function applyLayerScene(layer, scene) {
  let paths;
  try {
    const loading = typeof scene.loading === "function" ? scene.loading(layer) : scene.loading;
    paths = normalizeScenePaths(layer.from, loading, layer.to);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    throw new Error(`${layer.id}: ${message}`);
  }
  return {
    ...layer,
    ...paths,
    loadingOpacity: scene.loadingOpacity
  };
}
function applyPresetSceneDesign(asset) {
  const scene = presetScenes[asset.id];
  if (!scene) throw new Error(`Missing scene design for ${asset.id}.`);
  const layers = asset.layers.map((layer) => {
    const layerScene = scene.layers[layer.id];
    if (!layerScene) throw new Error(`Missing scene design for ${asset.id}/${layer.id}.`);
    return applyLayerScene(layer, layerScene);
  });
  if (Object.keys(scene.layers).length !== layers.length) throw new Error(`Scene design for ${asset.id} contains unknown layers.`);
  return {
    ...asset,
    loading: {
      enabled: true,
      label: scene.label,
      rotationCenter: scene.rotationCenter,
      rotationDirection: scene.rotationDirection,
      rotationDuration: scene.rotationDuration
    },
    layers
  };
}

